<?php
namespace OnKupon\Agent\Woo; class ProductLinker { public function register_shortcodes(): void { add_shortcode('onkupon_agent_product_card',[$this,'card']); add_shortcode('onkupon_agent_related_products',[$this,'related']); } public function card($atts): string { $id=absint($atts['id']??0); if(!$id) return ''; return '<div class="onkupon-product-card"><a href="'.esc_url(get_permalink($id)).'">'.esc_html(get_the_title($id)).'</a></div>'; } public function related($atts): string { $ids=array_filter(array_map('absint',explode(',',(string)($atts['ids']??'')))); return '<div class="onkupon-related-products">'.implode('',array_map(fn($id)=>$this->card(['id'=>$id]),$ids)).'</div>'; } }